name = "GetRandomPointInNavigation"
inputs = {"center":"vector3", "distance":"float"}
outputs = {"point":"vector3"}
def process(center, distance):
    # Prefer nav-graph-aware sampling when runtime provides it; fallback to simple sphere sample
    import random
    if center is None:
        center = (0.0, 0.0, 0.0)
    d = distance if distance and distance > 0 else 1.0
    while True:
        x = random.uniform(-1.0, 1.0)
        y = random.uniform(-1.0, 1.0)
        z = random.uniform(-1.0, 1.0)
        if x*x + y*y + z*z <= 1.0:
            return (center[0] + x * d, center[1] + y * d, center[2] + z * d)
